+    // operation in the transformed code may produce poison when the original code
+    // would not. For example, if the false value is infinity and the ninf flag is
+    // set, the transformed fmul would be poison even though the original select
+    // would have bypassed the poisonous operation entirely.
+    // Avoid the folding if the false value might violate any fast-math flags.
+    if (isa<FPMathOperator>(&SI)) {
+      KnownFPClass KFPC = computeKnownFPClass(FalseVal, FMF, fcAllFlags, &SI);
+      if ((FMF.noNaNs() && !KFPC.isKnownNeverNaN()) ||
+          (FMF.noInfs() && !KFPC.isKnownNeverInfinity()) ||
+          (FMF.noSignedZeros() && !KFPC.isKnownNeverZero()))
+        return nullptr;
+    }

     Value *NewSel = Builder.CreateSelect(SI.getCondition(), Swapped ? C : OOp,
